def _send_resend_doc(to_email, pdf_b64, doc_title, debtor=''):
    import json as _json
    import urllib.request as _ur
    import urllib.error as _ue
    # Sanitize subject: strip non-ASCII (mojibake from em-dashes etc.) and truncate to 200 chars
    _clean = lambda s: s.encode('ascii', errors='replace').decode('ascii').replace('?','').strip()
    subject = _clean(doc_title) + (f' - {_clean(debtor)}' if debtor else '')
    subject = (subject or 'Document')[:200]
    body_html = f'<html><body><p>Please find attached: <strong>{doc_title}</strong></p><p>Debtor: {debtor}</p><p>Sincerely,<br><strong>{ATTORNEY_NAME}</strong></p></body></html>'
    from_addr = f'{ATTORNEY_NAME} <{ATTORNEY_EMAIL}>'
    payload = _json.dumps({
        'from': from_addr,
        'to': [to_email],
        'subject': subject,
        'html': body_html,
        'attachments': [{'filename': doc_title.replace(' ','_') + '.pdf', 'content': pdf_b64}]
    }).encode()
    logger.info(f'Resend: from={from_addr} to={to_email} key_prefix={RESEND_API_KEY[:8] if RESEND_API_KEY else "MISSING"}')
    req = _ur.Request('https://api.resend.com/emails', data=payload,
        headers={
            'Authorization': f'Bearer {RESEND_API_KEY}',
            'Content-Type': 'application/json',
            'User-Agent': 'Mozilla/5.0 (compatible; ButcherLawDEE/1.0)'
        },
        method='POST')
    try:
        import json as _j
        with _ur.urlopen(req, timeout=30) as resp:
            result = _j.loads(resp.read())
            return {'ok': True, 'id': result.get('id')}
    except _ue.HTTPError as e:
        body = e.read().decode('utf-8', errors='replace')
        logger.error(f'Resend HTTPError {e.code}: {body}')
        return {'ok': False, 'error': f'HTTP {e.code}: {body}'}
    except Exception as e:
        logger.error(f'Resend error: {e}')
        return {'ok': False, 'error': str(e)}


def _send_fax_internal(fax_number, pdf_b64, doc_title, debtor=''):
    fax_email = f'{fax_number}@{REDFAX_DOMAIN}'
    return _send_resend_doc(to_email=fax_email, pdf_b64=pdf_b64, doc_title=doc_title, debtor=debtor)


def _send_mail_internal(to_name, to_street, to_city, to_state, to_zip, pdf_b64, doc_title, mail_type='usps_first_class'):
    import json as _json
    import urllib.request as _ur
    import base64 as _b64
    _clean = lambda s: s.encode('ascii', errors='replace').decode('ascii').replace('?','').strip() if s else s
    doc_title = _clean(doc_title)[:200]
    lob_body = {'description': f'{doc_title} - {to_name}', 'to': {'name': to_name, 'address_line1': to_street, 'address_city': to_city.strip(), 'address_state': to_state, 'address_zip': to_zip, 'address_country': 'US'}, 'from': {'name': f'{ATTORNEY_NAME}, {FIRM_NAME}', 'address_line1': FIRM_ADDRESS1, 'address_city': FIRM_CITY, 'address_state': FIRM_STATE, 'address_zip': FIRM_ZIP, 'address_country': 'US'}, 'color': False, 'double_sided': False, 'address_placement': 'insert_blank_page', 'mail_type': mail_type, 'file': f'<html><head></head><body><pdf src="data:application/pdf;base64,{pdf_b64}"/></body></html>'}
    auth = _b64.b64encode(f'{LOB_API_KEY}:'.encode()).decode()
    req = _ur.Request('https://api.lob.com/v1/letters', data=_json.dumps(lob_body).encode(), headers={'Authorization': f'Basic {auth}', 'Content-Type': 'application/json'}, method='POST')
    try:
        import json as _j
        with _ur.urlopen(req, timeout=30) as resp:
            result = _j.loads(resp.read())
            return {'ok': True, 'id': result.get('id'), 'expected_delivery': result.get('expected_delivery_date')}
    except Exception as e:
        import urllib.error as _ue
        if isinstance(e, _ue.HTTPError):
            body = e.read().decode('utf-8', errors='replace')
            logger.error(f'Lob mail HTTP error {e.code}: {body[:500]}')
            return {'ok': False, 'error': f'HTTP {e.code}: {body[:200]}'}
        logger.error(f'Lob mail error: {e}', exc_info=True)
        return {'ok': False, 'error': str(e)}

