        # Parse city/state/zip from "Portland, OR 97201" or "Portland OR 97201"
        import re as _re
        csz_match = _re.match(r'^(.+?),?\s+([A-Z]{2})\s+(\d{5}(?:-\d{4})?)$', to_csz.strip())
