        pdf_part = (
            f'--{boundary}\r\n'
            f'Content-Disposition: form-data; name="file"; filename="letter.pdf"\r\n'
            f'Content-Type: application/pdf\r\n\r\n'
        )
        body = (
            pdf_part.encode() + pdf_bytes +
            f'\r\n--{boundary}--\r\n'.encode()
        )

